    if serialization_method.lower() == "pickle":
        raise ValueError("pickle deserialization is not allowed due to security risks")

    try:
        if serialization_method == "json":
            # Decode bytes to string for JSON parsing
            if isinstance(serialized_bytes, bytes):
                data_str = serialized_bytes.decode('utf-8')
            else:
                data_str = serialized_bytes
            return json.loads(data_str)

        elif serialization_method == "csv":
            # Decode bytes to string for CSV parsing
            if isinstance(serialized_bytes, bytes):
                data_str = serialized_bytes.decode('utf-8')
            else:
                data_str = serialized_bytes

            # Parse CSV data
            csv_file = StringIO(data_str)
            reader = csv.DictReader(csv_file)
            return list(reader)

    except (json.JSONDecodeError, UnicodeDecodeError, csv.Error) as e:
        raise ValueError(f"Failed to deserialize data using '{serialization_method}': {str(e)}")

