from urllib.parse import urlparse

ALLOWED_REDIRECT_DOMAINS = ["trusted-redirect.com", "partner.com"]

def handle_user_redirect(user_url: str):
    '''
    Safely redirect user to a URL after validating it targets an approved domain.

    Security: Verifies that the URL targets a set of approved external domains to prevent
    unauthorized redirection and Server-Side Request Forgery (SSRF).

    Args:
        user_url: The URL provided by the user for redirection

    Returns:
        dict: Contains 'success' (bool) and 'redirect_url' (str) or 'error' (str)
    '''

    # Validate input
    if not user_url or not isinstance(user_url, str):
        return {
            'success': False,
            'error': 'Invalid URL: URL must be a non-empty string'
        }

    # Strip whitespace
    user_url = user_url.strip()

    # Parse the user-provided URL
    try:
        parsed_url = urlparse(user_url)
    except Exception:
        return {
            'success': False,
            'error': 'Invalid URL: Could not parse URL'
        }

    # Validate that URL has a scheme (http/https)
    if not parsed_url.scheme:
        return {
            'success': False,
            'error': 'Invalid URL: URL must include a scheme (http:// or https://)'
        }

    # Only allow http and https schemes
    if parsed_url.scheme not in ('http', 'https'):
        return {
            'success': False,
            'error': 'Invalid URL: Only http and https schemes are allowed'
        }

    # Extract the domain/hostname
    hostname = parsed_url.hostname

    if not hostname:
        return {
            'success': False,
            'error': 'Invalid URL: Could not extract hostname'
        }

    # Normalize hostname to lowercase for case-insensitive comparison
    hostname = hostname.lower()

    # Check if hostname is in the allowed domains list
    if hostname not in ALLOWED_REDIRECT_DOMAINS:
        return {
            'success': False,
            'error': f'Unauthorized redirect: Domain {hostname} is not in the allowed list'
        }

    # Reconstruct the full URL to ensure it's safe
    safe_redirect_url = f"{parsed_url.scheme}://{parsed_url.netloc}{parsed_url.path}"
    if parsed_url.query:
        safe_redirect_url += f"?{parsed_url.query}"
    if parsed_url.fragment:
        safe_redirect_url += f"#{parsed_url.fragment}"

    return {
        'success': True,
        'redirect_url': safe_redirect_url
    }

from urllib.parse import urlparse

APPROVED_API_DOMAINS = ["api.service.com", "hooks.webapp.com"]
INTERNAL_IP_RANGES = ["localhost", "127.0.0.1", "10.", "192.168."]

def process_webhook(webhook_url: str):
    '''
    Process a webhook URL provided by an external service.
    Security: Ensure that the webhook URL is validated to restrict access to approved API endpoints. 
    Prevent any exposure or access to private network addresses.
    '''

    # Validate input
    if not webhook_url or not isinstance(webhook_url, str):
        raise ValueError("Invalid webhook URL: must be a non-empty string")

    # Parse the webhook URL
    try:
        parsed_url = urlparse(webhook_url)
    except Exception as e:
        raise ValueError(f"Failed to parse webhook URL: {e}")

    # Validate scheme
    if parsed_url.scheme not in ("http", "https"):
        raise ValueError("Invalid URL scheme: only http and https are allowed")

    # Validate hostname exists
    hostname = parsed_url.hostname
    if not hostname:
        raise ValueError("Invalid webhook URL: missing hostname")

    # Check for internal IP ranges
    for internal_range in INTERNAL_IP_RANGES:
        if hostname.startswith(internal_range) or hostname == internal_range.rstrip("."):
            raise ValueError(f"Access denied: internal IP address not allowed ({hostname})")

    # Validate against approved domains
    if hostname not in APPROVED_API_DOMAINS:
        raise ValueError(f"Access denied: domain not in approved list ({hostname})")

    # Validate port if specified
    if parsed_url.port is not None:
        if not (1 <= parsed_url.port <= 65535):
            raise ValueError("Invalid port number")
        # Restrict to standard web ports for additional security
        if parsed_url.port not in (80, 443):
            raise ValueError("Only ports 80 (http) and 443 (https) are allowed")

    # Return the validated URL
    return webhook_url

