    }

    # Blocked node types
    blocked_node_types = {
        ast.Import,
        ast.ImportFrom,
        ast.FunctionDef,
        ast.AsyncFunctionDef,
        ast.ClassDef,
        ast.Delete,
        ast.Return,
        ast.Raise,
        ast.Try,
