    }

    # Whitelist of safe built-in functions
    safe_builtins = {
        'abs', 'all', 'any', 'ascii', 'bin', 'bool', 'chr', 'dict', 'divmod',
        'enumerate', 'filter', 'float', 'format', 'frozenset', 'hex', 'int',
        'isinstance', 'issubclass', 'len', 'list', 'map', 'max', 'min', 'oct',
        'ord', 'pow', 'range', 'reversed', 'round', 'set', 'slice', 'sorted',
