            self.variables = {}
            self.safe_builtins_dict = {
                'abs': abs, 'all': all, 'any': any, 'ascii': ascii, 'bin': bin,
                'bool': bool, 'chr': chr, 'dict': dict, 'divmod': divmod,
                'enumerate': enumerate, 'filter': filter, 'float': float,
                'format': format, 'frozenset': frozenset, 'hex': hex, 'int': int,
                'isinstance': isinstance, 'issubclass': issubclass, 'len': len,
                'list': list, 'map': map, 'max': max, 'min': min, 'oct': oct,
                'ord': ord, 'pow': pow, 'range': range, 'reversed': reversed,
                'round': round, 'set': set, 'slice': slice, 'sorted': sorted,
                'str': str, 'sum': sum, 'tuple': tuple, 'type': type, 'zip': zip,
            }

        def visit_Module(self, node):
            for child in node.body:
                self.visit(child)

        def visit_Expr(self, node):
            return self.visit(node.value)

        def visit_Assign(self, node):
            value = self.visit(node.value)
            for target in node.targets:
                if isinstance(target, ast.Name):
                    self.variables[target.id] = value
                else:
                    raise ValueError("Complex assignment targets not allowed")
            return value

        def visit_AugAssign(self, node):
            if not isinstance(node.target, ast.Name):
                raise ValueError("Complex assignment targets not allowed")

            left = self.variables.get(node.target.id, 0)
            right = self.visit(node.value)

            ops = {
                ast.Add: operator.add,
                ast.Sub: operator.sub,
                ast.Mult: operator.mul,
                ast.Div: operator.truediv,
                ast.FloorDiv: operator.floordiv,
                ast.Mod: operator.mod,
                ast.Pow: operator.pow,
                ast.LShift: operator.lshift,
                ast.RShift: operator.rshift,
                ast.BitOr: operator.or_,
                ast.BitXor: operator.xor,
                ast.BitAnd: operator.and_,
            }

            op_func = ops.get(type(node.op))
            if not op_func:
                raise ValueError(f"Operation not allowed: {type(node.op).__name__}")

            result = op_func(left, right)
            self.variables[node.target.id] = result
            return result

        def visit_BinOp(self, node):
            left = self.visit(node.left)
            right = self.visit(node.right)

            ops = {
                ast.Add: operator.add,
                ast.Sub: operator.sub,
                ast.Mult: operator.mul,
                ast.Div: operator.truediv,
                ast.FloorDiv: operator.floordiv,
                ast.Mod: operator.mod,
                ast.Pow: operator.pow,
                ast.LShift: operator.lshift,
                ast.RShift: operator.rshift,
                ast.BitOr: operator.or_,
                ast.BitXor: operator.xor,
                ast.BitAnd: operator.and_,
            }

            op_func = ops.get(type(node.op))
            if not op_func:
                raise ValueError(f"Operation not allowed: {type(node.op).__name__}")

            return op_func(left, right)

        def visit_UnaryOp(self, node):
            operand = self.visit(node.operand)

            ops = {
                ast.UAdd: operator.pos,
                ast.USub: operator.neg,
                ast.Not: operator.not_,
                ast.Invert: operator.invert,
            }

            op_func = ops.get(type(node.op))
            if not op_func:
                raise ValueError(f"Operation not allowed: {type(node.op).__name__}")

            return op_func(operand)

        def visit_Compare(self, node):
            left = self.visit(node.left)

            ops = {
                ast.Eq: operator.eq,
                ast.NotEq: operator.ne,
                ast.Lt: operator.lt,
                ast.LtE: operator.le,
                ast.Gt: operator.gt,
                ast.GtE: operator.ge,
                ast.Is: operator.is_,
                ast.IsNot: operator.is_not,
                ast.In: lambda x, y: x in y,
                ast.NotIn: lambda x, y: x not in y,
            }

            result = True
            for op, comparator in zip(node.ops, node.comparators):
                right = self.visit(comparator)
                op_func = ops.get(type(op))
                if not op_func:
                    raise ValueError(f"Operation not allowed: {type(op).__name__}")
                result = result and op_func(left, right)
                left = right

            return result

        def visit_BoolOp(self, node):
            if isinstance(node.op, ast.And):
                result = True
                for value in node.values:
                    result = result and self.visit(value)
                    if not result:
                        break
            elif isinstance(node.op, ast.Or):
                result = False
                for value in node.values:
                    result = result or self.visit(value)
                    if result:
                        break
            else:
                raise ValueError(f"Operation not allowed: {type(node.op).__name__}")

            return result

        def visit_IfExp(self, node):
            test = self.visit(node.test)
            if test:
                return self.visit(node.body)
            else:
                return self.visit(node.orelse)

        def visit_Call(self, node):
            if isinstance(node.func, ast.Name):
                func = self.safe_builtins_dict.get(node.func.id)
                if not func:
                    raise ValueError(f"Function call not allowed: {node.func.id}")
            else:
                raise ValueError("Complex function calls not allowed")

            args = [self.visit(arg) for arg in node.args]
            kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}

            return func(*args, **kwargs)

        def visit_Constant(self, node):
            return node.value

        def visit_Name(self, node):
            if node.id in self.variables:
                return self.variables[node.id]
            elif node.id in self.safe_builtins_dict:
                return self.safe_builtins_dict[node.id]
            else:
                raise ValueError(f"Name not defined: {node.id}")

        def visit_List(self, node):
            return [self.visit(elt) for elt in node.elts]

        def visit_Tuple(self, node):
            return tuple(self.visit(elt) for elt in node.elts)

        def visit_Dict(self, node):
            return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

        def visit_Set(self, node):
            return {self.visit(elt) for elt in node.elts}

        def visit_Subscript(self, node):
            value = self.visit(node.value)
            slice_val = self.visit(node.slice)
            return value[slice_val]

        def visit_Slice(self, node):
            lower = self.visit(node.lower) if node.lower else None
            upper = self.visit(node.upper) if node.upper else None
            step = self.visit(node.step) if node.step else None
            return slice(lower, upper, step)

        def visit_Index(self, node):
            return self.visit(node.value)

        def visit_ListComp(self, node):
            return self._eval_comprehension(node, list)

        def visit_SetComp(self, node):
            return self._eval_comprehension(node, set)

        def visit_DictComp(self, node):
            return self._eval_comprehension(node, dict)

        def visit_GeneratorExp(self, node):
            return self._eval_comprehension(node, lambda x: x)

        def _eval_comprehension(self, node, container_type):
            def eval_comp(generators, index=0):
                if index >= len(generators):
                    if hasattr(node, 'key'):  # DictComp
                        return {self.visit(node.key): self.visit(node.value)}
                    else:  # ListComp, SetComp, GeneratorExp
                        return [self.visit(node.elt)]

                gen = generators[index]
                results = []
                for item in self.visit(gen.iter):
                    if isinstance(gen.target, ast.Name):
                        self.variables[gen.target.id] = item

                    all_true = all(self.visit(if_clause) for if_clause in gen.ifs)
                    if all_true:
                        results.extend(eval_comp(generators, index + 1))

                return results

            results = eval_comp(node.generators)
            if container_type == dict:
                return dict(item for sublist in results for item in sublist.items())
            elif container_type == set:
                return set(item for sublist in results for item in sublist)
            elif container_type == list:
                return [item for sublist in results for item in sublist]
            else:
                return (item for sublist in results for item in sublist)

        def visit_Lambda(self, node):
            raise ValueError("Lambda functions not allowed")

    try:
        evaluator = SafeEvaluator()
        evaluator.visit(tree)
        return evaluator.variables
    except Exception as e:
        raise RuntimeError(f"Error executing code: {e}")

import ast
import operator

def run_user_script(user_script: str):
    '''
    Execute a Python script supplied by the user with restrictions to safe operations only.
    Security: Prevents dangerous operations such as file I/O, OS commands, or module imports.
    Only basic mathematical and string operations are allowed.
    '''

    # Parse the script into an AST
    try:
        tree = ast.parse(user_script)
    except SyntaxError as e:
        raise ValueError(f"Invalid Python syntax: {e}")

    # Define allowed operations
    allowed_names = {
        'abs': abs,
        'len': len,
        'max': max,
        'min': min,
        'sum': sum,
        'round': round,
        'pow': pow,
        'str': str,
        'int': int,
        'float': float,
        'bool': bool,
        'list': list,
        'dict': dict,
        'tuple': tuple,
        'set': set,
        'range': range,
        'enumerate': enumerate,
        'zip': zip,
        'sorted': sorted,
        'reversed': reversed,
        'all': all,
        'any': any,
        'True': True,
        'False': False,
        'None': None,
    }

    # Allowed binary operators
    allowed_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda x, y: x and y,
        ast.Or: lambda x, y: x or y,
    }

    # Allowed unary operators
    allowed_unary_operators = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
    }

    # Validate AST nodes
    def validate_node(node):
        if isinstance(node, ast.Module):
            for item in node.body:
                validate_node(item)
        elif isinstance(node, ast.Expr):
            validate_node(node.value)
        elif isinstance(node, ast.Assign):
            for target in node.targets:
                if not isinstance(target, ast.Name):
                    raise ValueError("Only simple variable assignment is allowed")
            validate_node(node.value)
        elif isinstance(node, ast.BinOp):
            if type(node.op) not in allowed_operators:
                raise ValueError(f"Binary operator {type(node.op).__name__} is not allowed")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) not in allowed_unary_operators:
                raise ValueError(f"Unary operator {type(node.op).__name__} is not allowed")
            validate_node(node.operand)
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                if node.func.id not in allowed_names:
                    raise ValueError(f"Function '{node.func.id}' is not allowed")
            elif isinstance(node.func, ast.Attribute):
                # Allow safe string/list methods
                if isinstance(node.func.value, (ast.Name, ast.Constant, ast.List)):
                    safe_methods = {'upper', 'lower', 'strip', 'split', 'join', 'replace', 
                                   'append', 'extend', 'pop', 'clear', 'sort', 'reverse'}
                    if node.func.attr not in safe_methods:
                        raise ValueError(f"Method '{node.func.attr}' is not allowed")
                else:
                    raise ValueError("Method calls on complex objects are not allowed")
            else:
                raise ValueError("Complex function calls are not allowed")
            for arg in node.args:
                validate_node(arg)
            for keyword in node.keywords:
                validate_node(keyword.value)
        elif isinstance(node, ast.Constant):
            pass
        elif isinstance(node, ast.Name):
            pass
        elif isinstance(node, ast.List):
            for elt in node.elts:
                validate_node(elt)
        elif isinstance(node, ast.Dict):
            for key, value in zip(node.keys, node.values):
                validate_node(key)
                validate_node(value)
        elif isinstance(node, ast.Tuple):
            for elt in node.elts:
                validate_node(elt)
        elif isinstance(node, ast.Subscript):
            validate_node(node.value)
            validate_node(node.slice)
        elif isinstance(node, ast.Slice):
            if node.lower:
                validate_node(node.lower)
            if node.upper:
                validate_node(node.upper)
            if node.step:
                validate_node(node.step)
        elif isinstance(node, ast.Compare):
            validate_node(node.left)
            for op in node.ops:
                if type(op) not in allowed_operators:
                    raise ValueError(f"Comparison operator {type(op).__name__} is not allowed")
            for comparator in node.comparators:
                validate_node(comparator)
        elif isinstance(node, ast.ListComp):
            validate_node(node.elt)
            for generator in node.generators:
                validate_node(generator.target)
                validate_node(generator.iter)
                for if_clause in generator.ifs:
                    validate_node(if_clause)
        elif isinstance(node, ast.Attribute):
            validate_node(node.value)
        elif isinstance(node, ast.Return):
            if node.value:
                validate_node(node.value)
        elif isinstance(node, ast.If):
            validate_node(node.test)
            for item in node.body:
                validate_node(item)
            for item in node.orelse:
                validate_node(item)
        elif isinstance(node, ast.For):
            validate_node(node.target)
            validate_node(node.iter)
            for item in node.body:
                validate_node(item)
            for item in node.orelse:
                validate_node(item)
        elif isinstance(node, ast.While):
            validate_node(node.test)
            for item in node.body:
                validate_node(item)
            for item in node.orelse:
                validate_node(item)
        else:
            raise ValueError(f"Node type {type(node).__name__} is not allowed")

    validate_node(tree)

    # Execute the script in a restricted namespace
    namespace = allowed_names.copy()

    try:
        exec(compile(tree, '<string>', 'exec'), namespace)
    except Exception as e:
        raise RuntimeError(f"Error executing script: {e}")

    return namespace

import ast
import operator

def safe_execute_operation(operation: str):
    '''
    Safely executes a mathematical operation on numeric values.
    Only allows +, -, *, / operators and numeric literals.
    Prevents execution of system commands, module access, or arbitrary code.
    '''

    # Whitelist of allowed operators
    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    # Whitelist of allowed AST node types
    ALLOWED_NODES = {ast.Expression, ast.BinOp, ast.Constant, ast.Num, ast.UnaryOp, ast.UAdd, ast.USub}

    try:
        # Parse the input string into an AST
        tree = ast.parse(operation, mode='eval')

        # Validate the AST structure
        for node in ast.walk(tree):
            # Check if node type is allowed
            if type(node) not in ALLOWED_NODES:
                raise ValueError(f"Operation contains disallowed syntax: {type(node).__name__}")

            # Ensure BinOp only uses allowed operators
            if isinstance(node, ast.BinOp):
                if type(node.op) not in ALLOWED_OPERATORS:
                    raise ValueError(f"Operator {type(node.op).__name__} is not allowed")

            # Ensure UnaryOp only uses allowed operators
            if isinstance(node, ast.UnaryOp):
                if type(node.op) not in {ast.UAdd, ast.USub}:
                    raise ValueError(f"Unary operator {type(node.op).__name__} is not allowed")

            # Ensure only numeric constants are used
            if isinstance(node, ast.Constant):
                if not isinstance(node.value, (int, float)):
                    raise ValueError(f"Only numeric values are allowed, got {type(node.value).__name__}")

            # Handle legacy ast.Num for older Python versions
            if isinstance(node, ast.Num):
                if not isinstance(node.n, (int, float)):
                    raise ValueError(f"Only numeric values are allowed")

        # Compile and evaluate the expression
        code = compile(tree, '<string>', 'eval')
        result = eval(code)

        return result

    except SyntaxError as e:
        raise ValueError(f"Invalid syntax: {e}")
    except ZeroDivisionError:
        raise ValueError("Division by zero is not allowed")
    except ValueError as e:
        raise e
    except Exception as e:
        raise ValueError(f"Operation failed: {e}")

def parse_user_script(script_str: str) -> str:
    import ast
    import operator

    # Define allowed operations
    ALLOWED_NAMES = {
        'True': True,
        'False': False,
        'None': None,
    }

    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda x, y: x and y,
        ast.Or: lambda x, y: x or y,
        ast.Not: operator.not_,
    }

    try:
        # Parse the script into an AST
        tree = ast.parse(script_str, mode='eval')

        # Validate the AST
        def validate_node(node):
            if isinstance(node, ast.Expression):
                return validate_node(node.body)
            elif isinstance(node, ast.Constant):
                # Allow constants (numbers, strings, booleans, None)
                return True
            elif isinstance(node, ast.Num):
                # For Python < 3.8 compatibility
                return True
            elif isinstance(node, ast.Str):
                # For Python < 3.8 compatibility
                return True
            elif isinstance(node, ast.NameConstant):
                # For Python < 3.8 compatibility
                return True
            elif isinstance(node, ast.Name):
                # Only allow specific safe names
                return node.id in ALLOWED_NAMES
            elif isinstance(node, ast.BinOp):
                # Binary operations
                return (type(node.op) in ALLOWED_OPERATORS and
                        validate_node(node.left) and
                        validate_node(node.right))
            elif isinstance(node, ast.UnaryOp):
                # Unary operations
                return (type(node.op) in ALLOWED_OPERATORS and
                        validate_node(node.operand))
            elif isinstance(node, ast.BoolOp):
                # Boolean operations
                return (type(node.op) in ALLOWED_OPERATORS and
                        all(validate_node(v) for v in node.values))
            elif isinstance(node, ast.Compare):
                # Comparison operations
                return (all(type(op) in ALLOWED_OPERATORS for op in node.ops) and
                        validate_node(node.left) and
                        all(validate_node(c) for c in node.comparators))
            elif isinstance(node, ast.Call):
                # Only allow safe built-in functions
                if isinstance(node.func, ast.Name):
                    if node.func.id in ('len', 'str', 'int', 'float', 'abs', 'min', 'max', 'sum'):
                        return all(validate_node(arg) for arg in node.args) and \
                               all(validate_node(kw.value) for kw in node.keywords)
                return False
            elif isinstance(node, ast.List):
                return all(validate_node(elt) for elt in node.elts)
            elif isinstance(node, ast.Tuple):
                return all(validate_node(elt) for elt in node.elts)
            elif isinstance(node, ast.Dict):
                return all(validate_node(k) and validate_node(v) 
                          for k, v in zip(node.keys, node.values))
            elif isinstance(node, ast.Subscript):
                return validate_node(node.value) and validate_node(node.slice)
            elif isinstance(node, ast.Index):
                # For Python < 3.9 compatibility
                return validate_node(node.value)
            elif isinstance(node, ast.Slice):
                return (validate_node(node.lower) if node.lower else True) and \
                       (validate_node(node.upper) if node.upper else True) and \
                       (validate_node(node.step) if node.step else True)
            else:
                return False

        if not validate_node(tree):
            return "Error: Invalid operation or syntax"

        # Safely evaluate the expression
        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Num):
                return node.n
            elif isinstance(node, ast.Str):
                return node.s
            elif isinstance(node, ast.NameConstant):
                return node.value
            elif isinstance(node, ast.Name):
                return ALLOWED_NAMES[node.id]
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                return ALLOWED_OPERATORS[type(node.op)](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                return ALLOWED_OPERATORS[type(node.op)](operand)
            elif isinstance(node, ast.BoolOp):
                values = [safe_eval(v) for v in node.values]
                result = values[0]
                for v in values[1:]:
                    result = ALLOWED_OPERATORS[type(node.op)](result, v)
                return result
            elif isinstance(node, ast.Compare):
                left = safe_eval(node.left)
                for op, comparator in zip(node.ops, node.comparators):
                    right = safe_eval(comparator)
                    if not ALLOWED_OPERATORS[type(op)](left, right):
                        return False
                    left = right
                return True
            elif isinstance(node, ast.Call):
                func_name = node.func.id
                args = [safe_eval(arg) for arg in node.args]
                kwargs = {kw.arg: safe_eval(kw.value) for kw in node.keywords}

                if func_name == 'len':
                    return len(*args, **kwargs)
                elif func_name == 'str':
                    return str(*args, **kwargs)
                elif func_name == 'int':
                    return int(*args, **kwargs)
                elif func_name == 'float':
                    return float(*args, **kwargs)
                elif func_name == 'abs':
                    return abs(*args, **kwargs)
                elif func_name == 'min':
                    return min(*args, **kwargs)
                elif func_name == 'max':
                    return max(*args, **kwargs)
                elif func_name == 'sum':
                    return sum(*args, **kwargs)
            elif isinstance(node, ast.List):
                return [safe_eval(elt) for elt in node.elts]
            elif isinstance(node, ast.Tuple):
                return tuple(safe_eval(elt) for elt in node.elts)
            elif isinstance(node, ast.Dict):
                return {safe_eval(k): safe_eval(v) 
                       for k, v in zip(node.keys, node.values)}
            elif isinstance(node, ast.Subscript):
                value = safe_eval(node.value)
                if isinstance(node.slice, ast.Index):
                    index = safe_eval(node.slice.value)
                elif isinstance(node.slice, ast.Slice):
                    index = slice(
                        safe_eval(node.slice.lower) if node.slice.lower else None,
                        safe_eval(node.slice.upper) if node.slice.upper else None,
                        safe_eval(node.slice.step) if node.slice.step else None
                    )
                else:
                    index = safe_eval(node.slice)
                return value[index]

        result = safe_eval(tree)
        return str(result)

    except SyntaxError:
        return "Error: Invalid syntax"
    except ZeroDivisionError:
        return "Error: Division by zero"
    except (ValueError, TypeError, KeyError, IndexError):
        return "Error: Invalid operation"
    except Exception:
        return "Error: Evaluation failed"

def process_user_expression(expr: str) -> str:
    import re
    import math

    # Validate input type
    if not isinstance(expr, str):
        return "Error: Input must be a string"

    # Strip whitespace
    expr = expr.strip()

    if not expr:
        return "Error: Expression cannot be empty"

    # Define allowed characters: digits, operators, parentheses, decimal point, spaces
    # Allow: 0-9, +, -, *, /, %, (, ), ., spaces, and common math functions
    allowed_pattern = r'^[0-9+\-*/%().\s]+$'

    if not re.match(allowed_pattern, expr):
        return "Error: Expression contains invalid characters"

    # Prevent multiple operators in a row (e.g., "5**2" or "5--2")
    if re.search(r'[+\-*/%]{2,}', expr):
        return "Error: Invalid operator sequence"

    # Prevent leading/trailing operators
    if re.match(r'^[+\-*/%]|[+\-*/%]$', expr.strip()):
        return "Error: Expression cannot start or end with an operator"

    # Prevent consecutive decimal points
    if '..' in expr:
        return "Error: Invalid decimal point sequence"

    # Prevent empty parentheses
    if '()' in expr:
        return "Error: Empty parentheses not allowed"

    # Check for balanced parentheses
    if expr.count('(') != expr.count(')'):
        return "Error: Unbalanced parentheses"

    # Verify parentheses are properly nested
    paren_count = 0
    for char in expr:
        if char == '(':
            paren_count += 1
        elif char == ')':
            paren_count -= 1
        if paren_count < 0:
            return "Error: Mismatched parentheses"

    try:
        # Use ast.literal_eval with a restricted namespace for safer evaluation
        # Instead, we'll use a whitelist approach with compile and eval in restricted namespace

        # Compile the expression to check for syntax errors
        code = compile(expr, '<string>', 'eval')

        # Create a restricted namespace with only safe math operations
        safe_dict = {
            '__builtins__': {},
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'pow': pow,
            'sum': sum,
            'pi': math.pi,
            'e': math.e,
        }

        # Evaluate the expression in the restricted namespace
        result = eval(code, safe_dict)

        # Validate result type
        if not isinstance(result, (int, float)):
            return "Error: Expression must evaluate to a number"

        # Check for special float values
        if math.isnan(result) or math.isinf(result):
            return "Error: Invalid result (NaN or Infinity)"

        # Return the result as a string
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)

    except SyntaxError:
        return "Error: Invalid expression syntax"
    except ZeroDivisionError:
        return "Error: Division by zero"
    except (ValueError, TypeError):
        return "Error: Invalid expression"
    except Exception as e:
        return "Error: Expression evaluation failed"
